 1	import type { FC, ReactElement } from 'react';
 2	import { useForkliftTranslation } from 'src/utils/i18n';
 3	
 4	import SectionHeading from '@components/headers/SectionHeading';
 5	import type { K8sResourceCondition } from '@kubev2v/types';
 6	import { HelperText, HelperTextItem, PageSection } from '@patternfly/react-core';
 7	
 8	import ConditionsTableItem from './ConditionsTableItem';
 9	
10	export type ConditionsSectionProps = {
11	  conditions?: K8sResourceCondition[];
12	};
13	
14	const ConditionsSection: FC<ConditionsSectionProps> = ({ conditions }): ReactElement => {
15	  const { t } = useForkliftTranslation();
16	
17	  return (
18	    <PageSection variant="light" className="forklift-page-section">
19	      <SectionHeading text={t('Conditions')} />
20	
21	      {conditions ? (
22	        <ConditionsTableItem conditions={conditions} />
23	      ) : (
24	        <HelperText>
25	          <HelperTextItem>{t('Conditions not found')}</HelperTextItem>
26	        </HelperText>
27	      )}
28	    </PageSection>
29	  );
30	};
31	
32	export default ConditionsSection;

